+export function expandQueryWithSynonyms(query: string): string {
+  const tokens = query.toLowerCase().split(/\s+/);
+  const expanded = tokens.flatMap((t) => [t, ...(SYNONYMS[t] ?? [])]);
+  return expanded.join(" ");
+}
